import { Component } from '@angular/core';
import { CommonModule } from '@angular/common'; 
import { FormsModule } from '@angular/forms';   

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent {
  services = [
    { title: 'PEDIATRICIANS' },
    { title: 'URANOLOGISTS' },
    { title: 'IMMUNOLOGISTS' }
  ];

  doctors = Array(12).fill(null).map((_, index) => ({
    name: `Doctor M${index + 1}`,
    specialty: 'MBBS, MD'
  }));

  contactData = {
    firstName: '',
    lastName: '',
    mobileNumber: '',
    email: '',
    message: ''
  };

  // ميزة الـ Smooth Scrolling للانتقال السلس الفوري بين الأقسام عند نقر الأزرار
  scrollToSection(sectionId: string) {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }

  onSignIn() {
    alert('Sign In menu triggered successfully!');
  }

  onRegister() {
    alert('Registration panel opened successfully!');
  }

  onPrevSlide() {
    console.log('Slider navigation active.');
  }

  onSubmit() {
    if (this.contactData.firstName) {
      alert(`Success! Message recorded for: ${this.contactData.firstName}`);
      this.contactData = { firstName: '', lastName: '', mobileNumber: '', email: '', message: '' };
    }
  }
}
